const records = [];

for (const item of $input.all()) {
  const datos = item.json;

  records.push({
    id: datos.id,
    fields: {
      Nombre: datos.Nombre || "Amiga",
      Email: datos.Email || "",
      Estado_Email: datos.Estado_Email,
      Correo1_Enviado: datos.Correo1_Enviado,
      Fecha_envio_1: datos.Fecha_envio_1
    }
  });
}

// Retorna el array directo sin envolver en json
return records;

