const records = [];

for (const item of $input.all()) {
  const datos = item.json;

  records.push({
    id: datos.id,
    fields: {
      Nombre: datos.Nombre || "Amiga",
      Email: datos.Email || "",
      Estado_Email: datos.Estado_Email,
      Correo4_Enviado: datos.Correo4_Enviado,
      Fecha_envio_4: datos.Fecha_envio_4
    }
  });
}

// Retorna el array directo sin envolver en json
return records;

const records = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const datos = items[i].json;

  records.push({
    json: {
      id: datos.id,
      Nombre: datos.Nombre || "Amiga",
      Email: datos.Email || "",
      Estado_Email: datos.Estado_Email,
      Correo5_Enviado: datos.Correo5_Enviado,
      Fecha_envio_5: datos.Fecha_envio_5
    },
    pairedItem: { item: i }
  });
}

return records;

